import numpy as np, os
def compute(pos_file):
    data = np.loadtxt(os.path.join('data', pos_file))
    np.random.seed(42)
    energies = np.array([])
    for i in range(len(data)):
        if data[i] == 0.0:
            energies = np.append(energies, 0)
        else:
            energies = np.append(energies, 1.0/data[i])
    return energies
